namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Title { get; set; }
    public required string Description { get; set; }
    public int Credits { get; set; }
    public required string Schedule { get; set; }
    public required string InstructorName { get; set; }
    public required string InstructorBio { get; set; }
    public required string DepartmentId { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public required string Id { get; set; }
    public required string Name { get; set; }
    public required string Description { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    public string? Name { get; set; }

    [Required(ErrorMessage = "Student ID is required.")]
    [Display(Name = "Student ID")]
    public string? StudentId { get; set; }

    [Required(ErrorMessage = "Please select a course.")]
    [Display(Name = "Course")]
    public int? CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = "math", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
        new() { Id = "eng", Name = "English", Description = "Literature, writing, and linguistic studies." },
        new() { Id = "phys", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = "hist", Name = "History", Description = "Exploration of past events, civilizations, and cultural development." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on CS pedagogy.", DepartmentId = "cs", IsFeatured = true },
        new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including divide-and-conquer, dynamic programming, and greedy algorithms.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. James Rodriguez", InstructorBio = "Dr. Rodriguez specializes in algorithm optimization and has industry experience at major tech companies.", DepartmentId = "cs", IsFeatured = true },
        new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, transaction processing, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Prof. Aisha Patel", InstructorBio = "Prof. Patel worked as a database architect for 10 years before joining academia. She researches distributed database systems.", DepartmentId = "cs", IsFeatured = false },
        new() { Id = 4, Code = "MATH 151", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is an award-winning educator with a passion for making calculus accessible to all students.", DepartmentId = "math", IsFeatured = true },
        new() { Id = 5, Code = "MATH 250", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Lisa Wang", InstructorBio = "Dr. Wang's research focuses on computational linear algebra and its applications in machine learning.", DepartmentId = "math", IsFeatured = false },
        new() { Id = 6, Code = "ENG 101", Title = "College Writing", Description = "Develop critical reading and writing skills through essay composition, argumentation, and research methods.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. David Kim", InstructorBio = "Prof. Kim is a published author and has taught writing at the university level for over 20 years.", DepartmentId = "eng", IsFeatured = false },
        new() { Id = 7, Code = "ENG 220", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present, exploring themes of identity, democracy, and culture.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Dr. Maria Gonzalez", InstructorBio = "Dr. Gonzalez specializes in 20th-century American fiction and has published three books on the subject.", DepartmentId = "eng", IsFeatured = true },
        new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:00 PM", InstructorName = "Dr. Robert Nguyen", InstructorBio = "Dr. Nguyen is an experimental physicist whose research involves particle detectors and quantum sensors.", DepartmentId = "phys", IsFeatured = false },
        new() { Id = 9, Code = "PHYS 205", Title = "Modern Physics", Description = "Introduction to special relativity, quantum mechanics, atomic structure, and nuclear physics.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Emily Carter", InstructorBio = "Dr. Carter's research in quantum information theory has been funded by multiple national grants.", DepartmentId = "phys", IsFeatured = true },
        new() { Id = 10, Code = "HIST 101", Title = "World Civilizations", Description = "A global survey of human civilizations from antiquity to 1500 CE, examining political, economic, and cultural developments.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Thomas Anderson", InstructorBio = "Dr. Anderson is a historian of the ancient Mediterranean world with extensive archaeological fieldwork experience.", DepartmentId = "hist", IsFeatured = false },
        new() { Id = 11, Code = "HIST 250", Title = "The Modern World", Description = "Major global developments from 1500 to the present, including colonialism, industrialization, world wars, and globalization.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", InstructorName = "Dr. Rachel Foster", InstructorBio = "Dr. Foster specializes in modern European history and comparative colonialism.", DepartmentId = "hist", IsFeatured = false },
        new() { Id = 12, Code = "MATH 320", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 2:00–2:50 PM", InstructorName = "Dr. Kevin Park", InstructorBio = "Dr. Park is a statistician with consulting experience in biotech and finance industries.", DepartmentId = "math", IsFeatured = false },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) =>
        _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) =>
        _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? search, string? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
        {
            query = query.Where(c => c.DepartmentId == departmentId);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }
}

