@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Courses - University Course Catalog</PageTitle>

<div class="container">
    <h1>Course Catalog</h1>

    <form method="get" action="/courses" class="row g-3 mb-4">
        <div class="col-md-6">
            <label for="search" class="form-label">Search</label>
            <input type="text" class="form-control" id="search" name="search" value="@Search" placeholder="Search by title, code, or instructor..." />
        </div>
        <div class="col-md-4">
            <label for="department" class="form-label">Department</label>
            <select class="form-select" id="department" name="department">
                <option value="">All Departments</option>
                @foreach (var dept in Catalog.GetDepartments())
                {
                    <option value="@dept.Id" selected="@(Department == dept.Id)">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2 d-flex align-items-end">
            <button type="submit" class="btn btn-primary w-100">Filter</button>
        </div>
    </form>

    @{
        var courses = Catalog.SearchCourses(Search, Department);
    }

    @if (courses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <p class="text-muted">Showing @courses.Count course(s)</p>
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead>
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Instructor</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in courses)
                    {
                        <tr>
                            <td>@course.Code</td>
                            <td>@course.Title</td>
                            <td>@Catalog.GetDepartment(course.DepartmentId)?.Name</td>
                            <td>@course.Credits</td>
                            <td>@course.InstructorName</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public string? Department { get; set; }
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<div class="container">
    <h1>Enrollment Request</h1>
    <p class="text-muted">Submit this form to request enrollment in a course.</p>

    @if (IsSubmitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Thank you, <strong>@Model.Name</strong>. Your enrollment request for
                <strong>@(Catalog.GetCourse(Model.CourseId ?? 0)?.Title)</strong> has been received.</p>
            <hr />
            <p class="mb-0">You will receive a confirmation via your student email.</p>
        </div>
        <a href="/enroll" class="btn btn-primary">Submit Another Request</a>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Back to Courses</a>
    }
    else
    {
        <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="needs-validation">
            <DataAnnotationsValidator />
            <AntiforgeryToken />

            <div class="row">
                <div class="col-md-8 col-lg-6">
                    <div class="mb-3">
                        <label for="name" class="form-label">Full Name</label>
                        <InputText id="name" class="form-control" @bind-Value="Model.Name" />
                        <ValidationMessage For="() => Model.Name" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g., STU-12345" />
                        <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course</label>
                        <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                            <option value="">-- Select a course --</option>
                            @foreach (var course in Catalog.GetAllCourses())
                            {
                                <option value="@course.Id">@course.Code - @course.Title</option>
                            }
                        </InputSelect>
                        <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                    </div>

                    <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                    <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                </div>
            </div>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool IsSubmitted { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && Model.CourseId is null)
        {
            Model.CourseId = CourseId;
        }
    }

    private void HandleSubmit()
    {
        IsSubmitted = true;
    }
}

